 1	import { ResourceLink, useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 2	import {
 3	  FormGroup,
 4	  FormHelperText,
 5	  FormSelect,
 6	  FormSelectOption,
 7	  HelperText,
 8	  HelperTextItem,
 9	} from '@patternfly/react-core';
10	import * as React from 'react';
11	import { Gateway } from './types';
12	import { useTranslation } from 'react-i18next';
13	
14	interface GatewaySelectProps {
15	  selectedGateway: Gateway;
16	  onChange: (updated: Gateway) => void;
17	}
18	
19	const GatewaySelect: React.FC<GatewaySelectProps> = ({ selectedGateway, onChange }) => {
20	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
21	  const [gateways, setGateways] = React.useState([]);
22	  const gvk = { group: 'gateway.networking.k8s.io', version: 'v1', kind: 'Gateway' };
23	
24	  const gatewayResource = {
25	    groupVersionKind: gvk,
26	    isList: true,
27	  };
28	
29	  const [gatewayData, gatewayLoaded, gatewayError] = useK8sWatchResource(gatewayResource);
30	
31	  React.useEffect(() => {
32	    if (gatewayLoaded && !gatewayError && Array.isArray(gatewayData)) {
33	      setGateways(
34	        gatewayData.map((gateway) => ({
35	          name: gateway.metadata.name,
36	          namespace: gateway.metadata.namespace,
37	        })),
38	      );
39	    }
40	  }, [gatewayData, gatewayLoaded, gatewayError]);
41	
42	  const handleGatewayChange = (event: React.FormEvent<HTMLSelectElement>) => {
43	    const [namespace, name] = event.currentTarget.value.split('/');
44	    onChange({ ...selectedGateway, name, namespace });
45	  };
46	
47	  return (
48	    <>
49	      <FormGroup label={t('Gateway API Target Reference')} isRequired fieldId="gateway-select">
50	        <FormSelect
51	          id="gateway-select"
52	          value={`${selectedGateway.namespace}/${selectedGateway.name}`}
53	          onChange={handleGatewayChange}
54	          aria-label={t('Select Gateway')}
55	        >
56	          <FormSelectOption
57	            key="placeholder"
58	            value=""
59	            label={t('Select a gateway')}
60	            isPlaceholder
61	          />
62	          {gateways.map((gateway, index) => (
63	            <FormSelectOption
64	              key={index}
65	              value={`${gateway.namespace}/${gateway.name}`}
66	              label={`${gateway.namespace}/${gateway.name}`}
67	            />
68	          ))}
69	        </FormSelect>
70	        <FormHelperText>
71	          <HelperText>
72	            <HelperTextItem>
73	              {t(
74	                'Gateway: Reference to a Kubernetes resource that the policy attaches to. To create an additional gateway go to',
75	              )}{' '}
76	              <ResourceLink
77	                groupVersionKind={gvk}
78	                title="Create a Gateway"
79	                hideIcon={true}
80	                inline={true}
81	                displayName="here"
82	              />
83	            </HelperTextItem>
84	          </HelperText>
85	        </FormHelperText>
86	      </FormGroup>
87	    </>
88	  );
89	};
90	
91	export default GatewaySelect;

